  4→// Field names rendered first in the sidebar, in order. Unknown fields follow alphabetically by label.
  5→export const PREFERRED_ORDER = ['name', 'city', 'state']
  6→
  7→export function sortFields(fields: SearchField[]): SearchField[] {
  8→  return [...fields].sort((a, b) => {
  9→    const ai = PREFERRED_ORDER.indexOf(a.name)
 10→    const bi = PREFERRED_ORDER.indexOf(b.name)
 11→    if (ai !== -1 && bi !== -1) return ai - bi
 12→    if (ai !== -1) return -1
 13→    if (bi !== -1) return 1
 14→    return a.label.localeCompare(b.label)
 15→  })
 16→}
